sys_script_include.script:
var VmsReferenceQualifier = Class.create();
VmsReferenceQualifier.prototype = Object.extendsObject(global.AbstractAjaxProcessor, {
    /**
     * Called from Catalog Client Script (onChange on branch) via GlideAjax.
     * Stores the selected branch sys_id in the user's session so the
     * reference qualifier can access it in the MRVS popup context.
     */
    storeBranchInSession: function() {
        var branch = this.getParameter('sysparm_branch');
        if (branch) {
            gs.getSession().putClientData('vms_selected_branch', branch);
        } else {
            gs.getSession().putClientData('vms_selected_branch', '');
        }
        return 'ok';
    },

    /**
     * Returns an encoded query to filter facility_inventory records by branch.
     * Reads the branch value from the user's session (stored by client script).
     * Falls back to current.variables and RP parameters for post-submission contexts.
     */
    getFacilityFilter: function() {
        var branch = '';

        // Primary: Read from session (stored by catalog client script via GlideAjax)
        try {
            branch = gs.getSession().getClientData('vms_selected_branch');
        } catch(e) {}

        // Fallback 1: Try current.variables (works on RITM form after submission)
        if (!branch) {
            try {
                if (typeof current !== 'undefined' && current && current.variables && current.variables.branch) {
                    branch = current.variables.branch.toString();
                }
            } catch(e) {}
        }

        // Fallback 2: Look up from cart/RITM via RP parameter
        if (!branch) {
            try {
                var cartId = RP.getParameterValue('sysparm_id');
                if (cartId) {
                    var cartItem = new GlideRecord('sc_cart_item');
                    if (cartItem.get(cartId) && cartItem.variables.branch) {
                        branch = cartItem.variables.branch.toString();
                    }
                    if (!branch) {
                        var ritm = new GlideRecord('sc_req_item');
                        if (ritm.get(cartId) && ritm.variables.branch) {
                            branch = ritm.variables.branch.toString();
                        }
                    }
                }
            } catch(e) {}
        }

        // Return the filter
        if (branch) {
            return 'branch=' + branch;
        }

        // No branch available - show nothing (user must select branch first)
        return 'sys_id=NULL';
    },

    type: 'VmsReferenceQualifier'
});
